import React, { useEffect, useState } from 'react';
import api from '../../services/api';
import {
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend,
  PieChart, Pie, Cell, ResponsiveContainer
} from 'recharts';
import Loader from '../common/Loader';
import { FeedbackStats } from '../../types';

const COLORS = ['#0088FE', '#00C49F', '#FFBB28', '#FF8042', '#8884d8', '#82ca9d'];

const AdminDashboard: React.FC = () => {
  const [stats, setStats] = useState<FeedbackStats | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => {
    fetchStats();
  }, []);

  const fetchStats = async () => {
    try {
      const response = await api.get('/api/feedback/stats');
      setStats(response.data.data || response.data);
    } catch (err) {
      setError('Failed to load statistics');
    } finally {
      setLoading(false);
    }
  };

  if (loading) return <Loader fullScreen text="Loading dashboard..." />;
  if (error) return <div style={styles.error}>{error}</div>;
  if (!stats) return <div style={styles.error}>No data available</div>;

  const ratingData = Object.entries(stats.ratingCounts || {}).map(([rating, count]) => ({
    rating: Number(rating),
    count,
  }));

  const wordRatingData = Object.entries(stats.wordRatingCounts || {}).map(([word, count]) => ({
    word,
    count,
  }));

  const topicData = Object.entries(stats.topicCounts || {})
    .map(([topic, count]) => ({ topic, count }))
    .sort((a, b) => b.count - a.count)
    .slice(0, 10);

  const mostCommonRating = Object.entries(stats.ratingCounts || {})
    .sort((a, b) => b[1] - a[1])[0]?.[0] || 'N/A';

  return (
    <div style={styles.container}>
      <h1 style={styles.title}>📈 Admin Dashboard</h1>
      <p style={styles.subtitle}>Real-time feedback analytics and insights</p>

      <div style={styles.summaryGrid}>
        <div style={styles.card}>
          <div style={styles.cardIcon}>📊</div>
          <div style={styles.cardTitle}>Total Feedbacks</div>
          <div style={styles.cardValue}>{stats.total || 0}</div>
        </div>
        <div style={styles.card}>
          <div style={styles.cardIcon}>⭐</div>
          <div style={styles.cardTitle}>Average Rating</div>
          <div style={styles.cardValue}>{stats.averageRating ? stats.averageRating.toFixed(1) : '0.0'}</div>
        </div>
        <div style={styles.card}>
          <div style={styles.cardIcon}>🏆</div>
          <div style={styles.cardTitle}>Most Common Rating</div>
          <div style={styles.cardValue}>{mostCommonRating}</div>
        </div>
        <div style={styles.card}>
          <div style={styles.cardIcon}>📚</div>
          <div style={styles.cardTitle}>Unique Topics</div>
          <div style={styles.cardValue}>{Object.keys(stats.topicCounts || {}).length}</div>
        </div>
      </div>

      <div style={styles.chartsGrid}>
        <div style={styles.chartCard}>
          <h3>Rating Distribution</h3>
          <ResponsiveContainer width="100%" height={300}>
            <BarChart data={ratingData}>
              <CartesianGrid strokeDasharray="3 3" />
              <XAxis dataKey="rating" />
              <YAxis />
              <Tooltip />
              <Legend />
              <Bar dataKey="count" fill="#8884d8" />
            </BarChart>
          </ResponsiveContainer>
        </div>

        <div style={styles.chartCard}>
          <h3>Word Rating Distribution</h3>
          <ResponsiveContainer width="100%" height={300}>
            <PieChart>
              <Pie
                data={wordRatingData}
                dataKey="count"
                nameKey="word"
                cx="50%"
                cy="50%"
                outerRadius={100}
                label
              >
                {wordRatingData.map((_, index) => (
                  <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                ))}
              </Pie>
              <Tooltip />
            </PieChart>
          </ResponsiveContainer>
        </div>

        <div style={styles.fullWidthChart}>
          <h3>Top 10 Topics</h3>
          <ResponsiveContainer width="100%" height={300}>
            <BarChart data={topicData} layout="vertical">
              <CartesianGrid strokeDasharray="3 3" />
              <XAxis type="number" />
              <YAxis type="category" dataKey="topic" width={250} />
              <Tooltip />
              <Legend />
              <Bar dataKey="count" fill="#82ca9d" />
            </BarChart>
          </ResponsiveContainer>
        </div>
      </div>
    </div>
  );
};

const styles: { [key: string]: React.CSSProperties } = {
  container: {
    padding: '2rem',
    maxWidth: '1400px',
    margin: '0 auto',
  },
  title: {
    fontSize: '1.75rem',
    marginBottom: '0.5rem',
    color: '#333',
  },
  subtitle: {
    color: '#666',
    marginBottom: '2rem',
  },
  summaryGrid: {
    display: 'grid',
    gridTemplateColumns: 'repeat(auto-fit, minmax(220px, 1fr))',
    gap: '1rem',
    marginBottom: '2rem',
  },
  card: {
    backgroundColor: 'white',
    borderRadius: '12px',
    padding: '1.5rem',
    textAlign: 'center',
    boxShadow: '0 2px 8px rgba(0,0,0,0.08)',
  },
  cardIcon: {
    fontSize: '2rem',
    marginBottom: '0.5rem',
  },
  cardTitle: {
    fontSize: '0.875rem',
    color: '#666',
    marginBottom: '0.5rem',
  },
  cardValue: {
    fontSize: '1.75rem',
    fontWeight: 'bold',
    color: '#333',
  },
  chartsGrid: {
    display: 'grid',
    gridTemplateColumns: '1fr 1fr',
    gap: '1.5rem',
  },
  chartCard: {
    backgroundColor: 'white',
    borderRadius: '12px',
    padding: '1.5rem',
    boxShadow: '0 2px 8px rgba(0,0,0,0.08)',
  },
  fullWidthChart: {
    backgroundColor: 'white',
    borderRadius: '12px',
    padding: '1.5rem',
    boxShadow: '0 2px 8px rgba(0,0,0,0.08)',
    gridColumn: 'span 2',
  },
  error: {
    textAlign: 'center',
    padding: '2rem',
    color: 'red',
  },
};

export default AdminDashboard;
